class Solution:
    def continuousSubarrays(self, nums):
        n = len(nums)
        count = 0
        for i in range(n):
            lo = hi = nums[i]
            for j in range(i, n):
                lo = min(lo, nums[j])
                hi = max(hi, nums[j])
                if hi - lo <= 2:
                    count += 1
                else:
                    break
        return count

