from collections import deque


class Solution:
    def continuousSubarrays(self, nums):
        n = len(nums)
        maxq = deque()
        minq = deque()
        left = 0
        total = 0
        for right in range(n):
            while maxq and nums[maxq[-1]] <= nums[right]:
                maxq.pop()
            maxq.append(right)
            while minq and nums[minq[-1]] >= nums[right]:
                minq.pop()
            minq.append(right)
            while nums[maxq[0]] - nums[minq[0]] > 2:
                left += 1
                if maxq[0] < left:
                    maxq.popleft()
                if minq[0] < left:
                    minq.popleft()
            total += right - left + 1
        return total

